(window.webpackJsonp=window.webpackJsonp||[]).push([[66],{538:function(t,e,n){"use strict";n.r(e);var r=n(0),o=Object(r.a)({},(function(){return this._self._c("ContentSlotsDistributor",{attrs:{"slot-key":this.$parent.slotKey}},[this._self._c("div",{domProps:{innerHTML:"<p>&lt;div class=&quot;custom-block tip&quot;&gt;&lt;p class=&quot;custom-block-title&quot;&gt;摘要&lt;/p&gt;\n在 3D 可视化场景中，设备标签、信息面板等 2D 元素的展示是刚需。本文介绍如何使用 CSS2DRenderer 在 Three.js 3D 场景中渲染高性能的 2D 标签，结合 OrbitControls 实现标签跟随、点击交互、信息弹窗等功能。\n&lt;/div&gt;</p>\n<h2>一、为什么选 CSS2DRenderer 而不是 Sprite？</h2>\n<p>Three.js 中展示文字标签有两种主流方案：</p>\n<table>\n<thead>\n<tr>\n<th>方案</th>\n<th>优点</th>\n<th>缺点</th>\n</tr>\n</thead>\n<tbody>\n<tr>\n<td><strong>Sprite + Canvas</strong></td>\n<td>纯 WebGL 渲染，无 DOM 开销</td>\n<td>文字模糊、交互困难、样式受限</td>\n</tr>\n<tr>\n<td><strong>CSS2DRenderer</strong></td>\n<td>原生 DOM、样式丰富、事件天然支持</td>\n<td>大量标签时 DOM 性能需关注</td>\n</tr>\n</tbody>\n</table>\n<p>在我们的机房运维管理系统中，设备数量在 100-200 之间，CSS2DRenderer 完全能胜任，且开发效率远高于 Sprite 方案。</p>\n<h2>二、基础集成</h2>\n<pre><code class=\"language-javascript\">import { CSS2DRenderer, CSS2DObject } from 'three/examples/jsm/renderers/CSS2DRenderer'\n\n// 初始化 CSS2D 渲染器\nconst labelRenderer = new CSS2DRenderer()\nlabelRenderer.setSize(window.innerWidth, window.innerHeight)\nlabelRenderer.domElement.style.position = 'absolute'\nlabelRenderer.domElement.style.top = '0'\nlabelRenderer.domElement.style.pointerEvents = 'none'\ndocument.getElementById('container').appendChild(labelRenderer.domElement)\n\n// 在动画循环中同步渲染\nfunction animate() {\n  requestAnimationFrame(animate)\n  renderer.render(scene, camera)\n  labelRenderer.render(scene, camera)\n}\n</code></pre>\n<h2>三、创建设备标签组件</h2>\n<p>我们封装了一个通用的标签创建方法：</p>\n<pre><code class=\"language-javascript\">function createDeviceLabel(device) {\n  const labelDiv = document.createElement('div')\n  labelDiv.className = 'device-label'\n  labelDiv.style.pointerEvents = 'auto'\n\n  labelDiv.innerHTML = `\n    &lt;div class=&quot;label-header&quot;&gt;\n      &lt;span class=&quot;status-dot ${device.status}&quot;&gt;&lt;/span&gt;\n      &lt;span class=&quot;device-name&quot;&gt;${device.name}&lt;/span&gt;\n    &lt;/div&gt;\n    &lt;div class=&quot;label-body&quot;&gt;\n      &lt;div class=&quot;info-row&quot;&gt;\n        &lt;span&gt;CPU:&lt;/span&gt;\n        &lt;span&gt;${device.cpu}%&lt;/span&gt;\n      &lt;/div&gt;\n      &lt;div class=&quot;info-row&quot;&gt;\n        &lt;span&gt;内存:&lt;/span&gt;\n        &lt;span&gt;${device.memory}%&lt;/span&gt;\n      &lt;/div&gt;\n      &lt;div class=&quot;info-row&quot;&gt;\n        &lt;span&gt;温度:&lt;/span&gt;\n        &lt;span&gt;${device.temp}°C&lt;/span&gt;\n      &lt;/div&gt;\n    &lt;/div&gt;\n  `\n\n  const label = new CSS2DObject(labelDiv)\n  label.position.set(0, 2, 0) // 标签位于设备上方\n  label.userData = { deviceId: device.id }\n\n  return label\n}\n</code></pre>\n<h3>标签样式</h3>\n<pre><code class=\"language-css\">.device-label {\n  background: rgba(0, 20, 40, 0.85);\n  border: 1px solid rgba(0, 180, 255, 0.6);\n  border-radius: 6px;\n  padding: 8px 12px;\n  color: #fff;\n  font-size: 12px;\n  backdrop-filter: blur(4px);\n  transition: all 0.3s ease;\n  cursor: pointer;\n  min-width: 120px;\n}\n\n.device-label:hover {\n  border-color: rgba(0, 180, 255, 1);\n  box-shadow: 0 0 15px rgba(0, 180, 255, 0.3);\n  transform: scale(1.05);\n}\n\n.status-dot {\n  display: inline-block;\n  width: 8px;\n  height: 8px;\n  border-radius: 50%;\n  margin-right: 6px;\n}\n\n.status-dot.online { background: #52c41a; }\n.status-dot.warning { background: #faad14; }\n.status-dot.offline { background: #ff4d4f; }\n</code></pre>\n<h2>四、标签显示/隐藏策略</h2>\n<p>100+ 个标签全部显示会非常混乱，我们实现了基于距离的显隐控制：</p>\n<pre><code class=\"language-javascript\">function updateLabelVisibility(camera, labels) {\n  const cameraPosition = camera.position\n  const maxDistance = 50 // 超过50单位距离隐藏标签\n\n  labels.forEach((label) =&gt; {\n    const worldPos = new THREE.Vector3()\n    label.getWorldPosition(worldPos)\n    const distance = cameraPosition.distanceTo(worldPos)\n\n    if (distance &gt; maxDistance) {\n      label.element.style.opacity = '0'\n      label.element.style.pointerEvents = 'none'\n    } else {\n      const opacity = 1 - (distance / maxDistance) * 0.5\n      label.element.style.opacity = String(opacity)\n      label.element.style.pointerEvents = 'auto'\n    }\n  })\n}\n</code></pre>\n<h2>五、点击交互与信息弹窗</h2>\n<p>标签因为是真实 DOM 元素，所以可以直接绑定事件：</p>\n<pre><code class=\"language-javascript\">labelDiv.addEventListener('click', (event) =&gt; {\n  event.stopPropagation()\n  // 显示设备详情弹窗\n  showDeviceDetail(device.id)\n\n  // 摄像机飞行到设备位置\n  flyToDevice(device.position, camera, controls)\n})\n\nfunction flyToDevice(targetPos, camera, controls) {\n  const offset = new THREE.Vector3(5, 5, 5)\n  const destination = targetPos.clone().add(offset)\n\n  gsap.to(camera.position, {\n    x: destination.x,\n    y: destination.y,\n    z: destination.z,\n    duration: 1.5,\n    ease: 'power2.inOut',\n    onUpdate: () =&gt; {\n      controls.target.copy(targetPos)\n      controls.update()\n    }\n  })\n}\n</code></pre>\n<h2>六、性能优化要点</h2>\n<ol>\n<li><strong>减少 DOM 操作</strong>：标签内容更新时使用 <code>textContent</code> 替代 <code>innerHTML</code></li>\n<li><strong>节流更新</strong>：设备数据不需要每帧刷新，使用定时器每 5 秒批量更新</li>\n<li><strong>虚拟标签</strong>：视口外的标签设置 <code>display: none</code> 而非仅修改 <code>opacity</code></li>\n<li><strong>分层渲染</strong>：将 <code>labelRenderer</code> 的 <code>pointerEvents</code> 设为 <code>none</code>，仅标签本身开启</li>\n</ol>\n<h2>七、总结</h2>\n<p>CSS2DRenderer 在中小型 3D 场景中是展示设备标签的最佳方案，开发效率高、样式灵活、交互自然。配合距离显隐策略和适当的性能优化，可以轻松支撑 200+ 设备标签的流畅展示。</p>\n"}})])}),[],!1,null,null,null);e.default=o.exports}}]);